from flask import Flask, request, redirect, url_for, render_template, flash
from flask_login import LoginManager, login_user, current_user
from urllib.parse import urlparse, urljoin

# hypothetical user model
from models import User

app = Flask(__name__)
app.config['SECRET_KEY'] = 'change-me'
login_manager = LoginManager(app)
login_manager.login_view = 'login'


def is_safe_url(target: str) -> bool:
    """Return True if the target URL is local to this site."""
    host_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return (
        test_url.scheme in ('http', 'https') and
        host_url.netloc == test_url.netloc
    )


@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))


@app.route('/login', methods=['GET', 'POST'])
def login():
    next_page = request.args.get('next')
    if current_user.is_authenticated:
        if next_page and is_safe_url(next_page):
            return redirect(next_page)
        return redirect(url_for('index'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        next_form = request.form.get('next')
        user = User.query.filter_by(username=username).first()
        if user and user.verify_password(password):
            login_user(user)
            redirect_target = next_form or next_page
            if redirect_target and is_safe_url(redirect_target):
                return redirect(redirect_target)
            return redirect(url_for('index'))
        flash('Invalid credentials', 'error')
    return render_template('login.html', next=next_page or '')


@app.route('/')
def index():
    return 'Home Page'


if __name__ == '__main__':
    app.run(debug=True)